import test from 'node:test';
import assert from 'node:assert/strict';

import { resetFlights } from '../src/inflight.ts';
import { loadUser } from '../src/user_service.ts';

test('concurrent successful loads share one provider call', async () => {
  resetFlights();
  let calls = 0;
  const provider = async () => {
    calls += 1;
    await new Promise((resolve) => setTimeout(resolve, 5));
    return 'alice';
  };
  const [first, second] = await Promise.all([loadUser('u-1', provider), loadUser('u-1', provider)]);
  assert.deepEqual([first, second], ['alice', 'alice']);
  assert.equal(calls, 1);
});
